import java.util.Arrays;

public class SortBenchmark {
    static long comparisons;

    static void bubbleSort(int[] arr) {
        int n = arr.length;
        comparisons = 0;
        for (int i = 0; i < n-1; i++)
            for (int j = 0; j < n-i-1; j++) {
                comparisons++;
                if (arr[j] > arr[j+1]) { int t=arr[j]; arr[j]=arr[j+1]; arr[j+1]=t; }
            }
    }

    static void merge(int[] arr, int l, int m, int r) {
        int[] left = Arrays.copyOfRange(arr, l, m+1);
        int[] right = Arrays.copyOfRange(arr, m+1, r+1);
        int i=0, j=0, k=l;
        while (i<left.length && j<right.length) {
            comparisons++;
            if (left[i] <= right[j]) arr[k++]=left[i++];
            else arr[k++]=right[j++];
        }
        while (i<left.length) arr[k++]=left[i++];
        while (j<right.length) arr[k++]=right[j++];
    }

    static void mergeSort(int[] arr, int l, int r) {
        if (l < r) {
            int m = (l+r)/2;
            mergeSort(arr, l, m);
            mergeSort(arr, m+1, r);
            merge(arr, l, m, r);
        }
    }

    public static void main(String[] args) {
        int[] base = {64, 34, 25, 12, 22, 11, 90, 55, 43, 77};

        int[] a1 = base.clone();
        bubbleSort(a1);
        long bubbleCmp = comparisons;

        int[] a2 = base.clone();
        comparisons = 0;
        mergeSort(a2, 0, a2.length-1);
        long mergeCmp = comparisons;

        // TODO: Print sorted arrays and comparison counts
        System.out.println("Bubble sorted: " + Arrays.toString(a1));
        System.out.println("Bubble comparisons: " + bubbleCmp);
        System.out.println("Merge sorted:  " + Arrays.toString(a2));
        System.out.println("Merge comparisons:  " + mergeCmp);
        System.out.println("Merge is faster: " + (mergeCmp < bubbleCmp));
    }
}

import java.util.Arrays;

public class SmartSorter {

    void insertionSort(int[] arr) {
        for (int i=1;i<arr.length;i++){
            int key=arr[i], j=i-1;
            while(j>=0 && arr[j]>key){ arr[j+1]=arr[j]; j--; }
            arr[j+1]=key;
        }
    }

    void mergeSort(int[] arr, int l, int r) {
        if(l>=r) return;
        int m=(l+r)/2;
        mergeSort(arr,l,m); mergeSort(arr,m+1,r);
        int[] tmp=Arrays.copyOfRange(arr,l,r+1);
        int i=0,j=m-l+1,k=l;
        while(i<=m-l && j<tmp.length) arr[k++]=(tmp[i]<=tmp[j])?tmp[i++]:tmp[j++];
        while(i<=m-l) arr[k++]=tmp[i++];
        while(j<tmp.length) arr[k++]=tmp[j++];
    }

    void quickSort(int[] arr, int lo, int hi) {
        if(lo>=hi) return;
        int pivot=arr[hi], i=lo;
        for(int j=lo;j<hi;j++) if(arr[j]<=pivot){int t=arr[i];arr[i]=arr[j];arr[j]=t;i++;}
        int t=arr[i];arr[i]=arr[hi];arr[hi]=t;
        quickSort(arr,lo,i-1); quickSort(arr,i+1,hi);
    }

    int countInversions(int[] arr) {
        int c=0;
        for(int i=0;i<arr.length;i++) for(int j=i+1;j<arr.length;j++) if(arr[i]>arr[j]) c++;
        return c;
    }

