    public static void main(String[] args) {
        SmartSorter ss = new SmartSorter();

        int[] small = {5,2,8,1,9};
        ss.smartSort(small);
        System.out.println(Arrays.toString(small));

        int[] nearlySorted = {1,2,3,5,4,6,7,8,9,10,11,12};
